 34→public class TaskExecutionMetadataTest {
 35→    static final String TOPOLOGY1 = "topology1";
 36→    static final String TOPOLOGY2 = "topology2";
 37→    static final Set<String> NAMED_TOPOLOGIES = Set.of(TOPOLOGY1, TOPOLOGY2);
 38→    static final int TIME_ZERO = 0;
 39→    static final int CONSTANT_BACKOFF_MS = 5000;
 40→
 41→    @Test
 42→    public void testCanProcessWithoutNamedTopologies() {
 43→        final Set<String> topologies = Collections.singleton(UNNAMED_TOPOLOGY);
 44→        final Set<String> pausedTopologies = new HashSet<>();
 45→
 46→        final TaskExecutionMetadata metadata = new TaskExecutionMetadata(topologies, pausedTopologies, ProcessingMode.AT_LEAST_ONCE);
 47→
 48→        final Task mockTask = createMockTask(UNNAMED_TOPOLOGY);
 49→
 50→        assertTrue(metadata.canProcessTask(mockTask, TIME_ZERO));
 51→        // This pauses an UNNAMED_TOPOLOGY / a KafkaStreams instance without named/modular
 52→        // topologies.
 53→        pausedTopologies.add(UNNAMED_TOPOLOGY);
 54→        assertFalse(metadata.canProcessTask(mockTask, TIME_ZERO));
 55→    }
 56→
 57→    @Test
 58→    public void testNamedTopologiesCanBePausedIndependently() {
 59→        final Set<String> pausedTopologies = new HashSet<>();
 60→        final TaskExecutionMetadata metadata = new TaskExecutionMetadata(NAMED_TOPOLOGIES, pausedTopologies, ProcessingMode.AT_LEAST_ONCE);
 61→
 62→        final Task mockTask1 = createMockTask(TOPOLOGY1);
 63→        final Task mockTask2 = createMockTask(TOPOLOGY2);
 64→
 65→        assertTrue(metadata.canProcessTask(mockTask1, TIME_ZERO));
 66→        assertTrue(metadata.canProcessTask(mockTask2, TIME_ZERO));
 67→
 68→        pausedTopologies.add(TOPOLOGY1);
 69→        assertFalse(metadata.canProcessTask(mockTask1, TIME_ZERO));
 70→        assertTrue(metadata.canProcessTask(mockTask2, TIME_ZERO));
 71→
 72→        pausedTopologies.remove(TOPOLOGY1);
 73→        assertTrue(metadata.canProcessTask(mockTask1, TIME_ZERO));
 74→        assertTrue(metadata.canProcessTask(mockTask2, TIME_ZERO));
 75→    }
 76→
 77→    @Test
 78→    public void testNamedTopologiesCanBeStartedPaused() {
 79→        final Set<String> pausedTopologies = new HashSet<>();
 80→        pausedTopologies.add(TOPOLOGY1);
 81→
 82→        final TaskExecutionMetadata metadata = new TaskExecutionMetadata(NAMED_TOPOLOGIES, pausedTopologies, ProcessingMode.AT_LEAST_ONCE);
 83→
 84→        final Task mockTask1 = createMockTask(TOPOLOGY1);
 85→        final Task mockTask2 = createMockTask(TOPOLOGY2);
 86→
 87→        assertFalse(metadata.canProcessTask(mockTask1, TIME_ZERO));
 88→        assertTrue(metadata.canProcessTask(mockTask2, TIME_ZERO));
 89→
 90→        pausedTopologies.remove(TOPOLOGY1);
 91→        assertTrue(metadata.canProcessTask(mockTask1, TIME_ZERO));
 92→        assertTrue(metadata.canProcessTask(mockTask2, TIME_ZERO));
 93→    }
 94→
 95→    @Test
 96→    public void testNamedTopologiesCanBackoff() {
 97→        final Set<String> pausedTopologies = new HashSet<>();
 98→
 99→        final TaskExecutionMetadata metadata = new TaskExecutionMetadata(NAMED_TOPOLOGIES, pausedTopologies, ProcessingMode.AT_LEAST_ONCE);
100→
101→        final Task mockTask1 = createMockTask(TOPOLOGY1);
102→        final Task mockTask2 = createMockTask(TOPOLOGY2);
103→
104→        assertTrue(metadata.canProcessTask(mockTask1, TIME_ZERO));
105→        assertTrue(metadata.canProcessTask(mockTask2, TIME_ZERO));
106→
107→        metadata.registerTaskError(mockTask1, new Throwable("Error"), TIME_ZERO);
108→        assertFalse(metadata.canProcessTask(mockTask1, CONSTANT_BACKOFF_MS - 1));
109→        assertTrue(metadata.canProcessTask(mockTask2, CONSTANT_BACKOFF_MS - 1));
110→
111→        assertFalse(metadata.canProcessTask(mockTask1, CONSTANT_BACKOFF_MS));
112→        assertTrue(metadata.canProcessTask(mockTask2, CONSTANT_BACKOFF_MS));
113→
114→        assertTrue(metadata.canProcessTask(mockTask1, CONSTANT_BACKOFF_MS + 1));
115→        assertTrue(metadata.canProcessTask(mockTask2, CONSTANT_BACKOFF_MS + 1));
116→    }
117→
118→    private static Task createMockTask(final String topologyName) {
119→        final Task mockTask = mock(Task.class);
120→        final TaskId taskId = new TaskId(0, 0, topologyName);
121→        when(mockTask.id()).thenReturn(taskId);
122→        return mockTask;
123→    }
124→}
